    bool chainWorked = (observer1->getCallCount() > 0) && (observer2->getCallCount() > 0);

    // 7. Calculate total call count
    int totalCallCount = observer1->getCallCount() + observer2->getCallCount();

    // 8. Return results
    return {totalCallCount, chainWorked};
