    // 9. Attempt to lock mutex with safety enabled
    bool lockedWithSafety = false;
    {
        reaction::ConditionalLockGuard<reaction::ConditionalMutex> guard(mutex);
        // Lock is automatically acquired by the guard constructor
        lockedWithSafety = true; // If we reach here, lock was acquired
    } // 10. Exit guard scope

