    second_ptr->add(delta);

    // 8. Get current value after second add
    int value_after_second_add = reactive_counter.get().value;

    // 9. Check if pointer is stable (compare by value, not by reference)
    bool pointers_stable = (*first_ptr == *second_ptr);

